   558	fn request_permissions(
   559	    request: &Request,
   560	    access: RepositoryAccess,
   561	    viewer_user_id: Option<&str>,
   562	) -> RequestPermissionsResponse {
   563	    let maintainer = matches!(
   564	        access.actor,
   565	        RepositoryActor::Owner | RepositoryActor::Member
   566	    );
   567	    let author = viewer_user_id == Some(request.author_user_id.as_str());
   568	    let editor = viewer_user_id
   569	        .map(|user_id| request.editor_user_ids.contains(user_id))
   570	        .unwrap_or(false);
   571	    let can_edit_branch = author || editor || maintainer;
   572	    let open = !matches!(
   573	        request.state,
   574	        RequestState::Resolved | RequestState::Withdrawn
   575	    );
   576	    let submitted = request.state == RequestState::Submitted;
   577	    let submitted_or_waiting = matches!(
   578	        request.state,
   579	        RequestState::Submitted | RequestState::NeedsResponse
   580	    );
   581	    RequestPermissionsResponse {
   582	        can_comment: open && can_edit_branch,
   583	        can_pull_branch: open && can_edit_branch && request.git_snapshot.is_some(),
   584	        can_push_branch: open && can_edit_branch,
   585	        can_delete: open && (author || maintainer),
   586	        can_invite_editor: open && maintainer,
   587	        can_mark_needs_response: submitted && maintainer,
   588	        can_respond: open && author && request.state == RequestState::NeedsResponse,
   589	        can_resolve: submitted_or_waiting && maintainer,
   590	        can_merge: submitted && maintainer,
   591	    }
   592	}
